
import {  compose, createAsyncThunk, createSlice } from "@reduxjs/toolkit"
 import axios from "axios"


export const getSubject = createAsyncThunk(
  "getSubject",
  async(classId)=>{
const SubjectData =  await axios.get(`http://localhost:3000/subject/${classId}`)
return SubjectData.data
  } 
)


export const getChapter = createAsyncThunk(
  "getChapter",
  async({classId,subjectId})=>{
    const ChapterData = await axios.get(`http://localhost:3000/chapter/${classId}/${subjectId}`)
    return ChapterData.data
  }
)

export const getLevel = createAsyncThunk(
  "getLevel",
  async({classId,subjectId, chapterId})=>{
    const LevelData = await axios.get(`http://localhost:3000/level/${classId}/${subjectId}/${chapterId}`)
    return LevelData.data;
  }
)

export const getQuestion = createAsyncThunk(
  "getQuestion",
  async({classId,subjectId, chapternumId, levelId})=>{
    const QuestionData = await axios.get(`http://localhost:3000/question/${classId}/${subjectId}/${chapternumId}/${levelId}`);
    return QuestionData.data;
  }
)

